import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.DnrXFDHb.js";const x=JSON.parse('{"title":"G14: 新業務展望 — 產品趨勢研究員審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/8103_瀚荃/20260425/G14_新業務展望_產品趨勢研究員.md","filePath":"審計報告庫/經營審計/8103_瀚荃/20260425/G14_新業務展望_產品趨勢研究員.md"}'),d={name:"審計報告庫/經營審計/8103_瀚荃/20260425/G14_新業務展望_產品趨勢研究員.md"};function n(s,t,i,o,g,f){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="g14-新業務展望-—-產品趨勢研究員審計報告" tabindex="-1">G14: 新業務展望 — 產品趨勢研究員審計報告 <a class="header-anchor" href="#g14-新業務展望-—-產品趨勢研究員審計報告" aria-label="Permalink to &quot;G14: 新業務展望 — 產品趨勢研究員審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>公司在最近三年中是否有增加新的業務展望或第二成長曲線？其技術儲備與市場佈局進度為何？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>瀚荃三力佈局中，AI Power已進入放量期（營收占比18%→21%）為真實第二曲線，訂單能見度至2026年7月且產能滿載；新能源為潛在曲線（無Design-win及認證公告），轉單效應尚待驗證；機器人屬期權型（量產目標2027底），時程仍遠。AI Power為當前唯一可靠成長動能。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>A（良）</strong> — AI Power方向正確且已放量，惟新能源/機器人仍處早期；評級依賴主力曲線表現，需觀察其餘曲線兌現。</p><table tabindex="0"><thead><tr><th style="text-align:left;">評估維度</th><th style="text-align:left;">狀態</th><th style="text-align:left;">關鍵證據</th></tr></thead><tbody><tr><td style="text-align:left;">賽道趨勢</td><td style="text-align:left;">優</td><td style="text-align:left;">AI伺服器CAGR 34%；瀚荃完全順勢</td></tr><tr><td style="text-align:left;">Design-win</td><td style="text-align:left;">良</td><td style="text-align:left;">已打入台達電，CSP ASIC新訂單放量中</td></tr><tr><td style="text-align:left;">營收量化</td><td style="text-align:left;">良</td><td style="text-align:left;">AI占比5%→21%，目標30%+</td></tr><tr><td style="text-align:left;">新能源</td><td style="text-align:left;">中</td><td style="text-align:left;">僅定性描述，無具體認證公告</td></tr><tr><td style="text-align:left;">機器人</td><td style="text-align:left;">中</td><td style="text-align:left;">戴盟合作開發中，量產&gt;1.5年</td></tr><tr><td style="text-align:left;">產能擴充</td><td style="text-align:left;">良</td><td style="text-align:left;">越南廠量產，2026擴20%-30%</td></tr></tbody></table><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p><strong>AI Power</strong>：大電流板端連接器供貨台達電等電源大廠，用於PSU/BBU/CSP ASIC平台。營收占比從2024年~5%升至2025年18%、2026年前2月21%，全年目標30%+。BBU已量產，HVDC處樣品階段。訂單能見度至2026年7月，產能滿載。該產品ASP較傳統連接器高約二至三倍，毛利率貢獻顯著，已成為瀚荃2025全年毛利率回升至37%以上的關鍵推手。</p><p><strong>新能源</strong>：FPC排線升級應用於電池包電力分配，靠東南亞產能受惠去中化，但無Design-win或認證公告，尚無實質營收貢獻。對比同業如貿聯已在電動車電池組取得Tier 1認證，瀚荃新能源進度至少落後一年半以上，需加速追趕。</p><p><strong>機器人</strong>：與戴盟合作超薄可折彎線供人形機器人關節，成本僅傳統方案1/3；2026年初收購全宇昕15%股權整合IC設計。量產目標2027年底。然而人形機器人整體市場2025年仍屬萌芽期，終端應用場景不明確，量產延後至2028年以後的風險不可忽視。</p><p><strong>賽道對位</strong>：AI伺服器TAM 2024年1,429億→2030年8,378億美元（CAGR 34%）；人形機器人2024年14億→2030年110億（CAGR 43%）；新能源連接器CAGR估15-20%。三條賽道皆處於高成長階段，惟時序落差大——AI已放量、新能源仍需二至三年醞釀、機器人則需三至五年觀察。</p><p><strong>產能驗證</strong>：越南廠2025/11量產，泰國新廠2026申請ISO；中國五廠整併為三座；2026擴產20-30%，以自有資金支應。兩岸三地產能分散策略有助於應對關稅壁壘與地緣風險，惟跨國管理成本與幹部佈局將是執行面關鍵變數。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p><strong>五大阻力</strong>：①AI週期回調風險——占比若達30%+，依賴性過高，追蹤CSP資本開支及訂單能見度變化；②連接器壁壘有限——泰科/安費諾/立訊可能價格戰，毛利率須維持37-40%以上，惟立訊在中國本土具備成本優勢，若其跨入AI伺服器領域恐形成價格侵蝕壓力；③新能源/機器人「說故事」鴻溝——連續兩季無認證進展應下調評級，目前兩項業務營收貢獻接近零，若再過二季度仍無實質進度，市場恐重新定價其估值溢價；④東南亞產能執行風險——幹部不足恐延誤良率爬坡，追蹤泰國廠ISO時程，越南廠量產初期良率若低於85%將拖累整體毛利率；⑤匯率警訊——2025H1新台幣升值吃掉四成稅前淨利，外銷占比逾七成使匯率波動成為常態性利空，應以營業利益為核心指標而非稅後淨利。<strong>顛覆風險</strong>（遠期）：矽光子/無線供電成熟後可能替代連接器，但3~5年內不影響評級。此外，CSP客戶如微軟、Meta自研ASIC晶片供應鏈若發生供應商重組，瀚荃新切入的ASIC平台訂單可能面臨砍單或降價的惡化風險。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">證據項目</th><th style="text-align:left;">來源</th></tr></thead><tbody><tr><td style="text-align:left;">月營收（2022-2026Q1）、損益表（2022Q1-2025Q4）</td><td style="text-align:left;">FinMind API</td></tr><tr><td style="text-align:left;">2025/12 法說會備忘錄</td><td style="text-align:left;">富果 Fugle Blog</td></tr><tr><td style="text-align:left;">2026三箭齊發策略、線材到人形機器人</td><td style="text-align:left;">經濟日報/聯合報（2026/04/10）</td></tr><tr><td style="text-align:left;">AI電源需求強勁</td><td style="text-align:left;">旺得富理財網</td></tr><tr><td style="text-align:left;">AI Server CAGR 34.3%</td><td style="text-align:left;">MarketsandMarkets</td></tr><tr><td style="text-align:left;">人形機器人CAGR 42.8%</td><td style="text-align:left;">BCC Research</td></tr><tr><td style="text-align:left;">112年年報</td><td style="text-align:left;">瀚荃官網</td></tr><tr><td style="text-align:left;">兩大ASIC訂單/目標價143元</td><td style="text-align:left;">理財周刊</td></tr></tbody></table><p><strong>審計身分</strong>：Deep32Q L3 產品趨勢研究員 (product-trend-researcher) — 2026-04-25</p>',19)])])}const _=e(d,[["render",n]]);export{x as __pageData,_ as default};
